parameters.jsCode:
const client = $input.item.json;

// Generate unique promo code
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
const rnd = Array.from({length: 8}, () => chars[Math.floor(Math.random()*chars.length)]).join('');
const code = 'REA-' + rnd;

// Expiry: 3 days from now
const validUntil = new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString();

// Email content by language
const lang = (client.language || 'ru').toLowerCase();

const subjects = {
  ru: 'Скучаем по тебе! −20% на следующий заказ ☕',
  pl: 'Tęsknimy za Tobą! −20% na kolejne zamówienie ☕',
  ua: 'Сумуємо за тобою! −20% на наступне замовлення ☕'
};

const bodies = {
  ru: `<html><body style="font-family:sans-serif;color:#1F2937;max-width:560px;margin:auto;padding:24px">
<p style="font-size:22px;font-weight:700;margin-bottom:8px">☕ Давно не виделись!</p>
<p style="color:#6B7280;margin-bottom:20px">Мы заметили, что вы не делали заказы в Coffee Verve уже больше 90 дней.</p>
<p style="margin-bottom:16px">В подарок — персональный промокод на <strong style="color:#16A34A">−20%</strong> на любой заказ:</p>
<div style="background:#F0FDF4;border:2px solid #86EFAC;border-radius:12px;padding:20px;text-align:center;margin-bottom:20px">
  <span style="font-size:28px;font-weight:800;letter-spacing:0.1em;color:#15803D">${code}</span>
  <p style="color:#6B7280;font-size:12px;margin-top:8px">Действует 3 дня</p>
</div>
<a href="https://shop.coffee-verve.com/ru" style="display:block;background:#2C1810;color:#fff;text-align:center;padding:14px 24px;border-radius:10px;text-decoration:none;font-weight:600;margin-bottom:20px">Перейти в магазин</a>
<p style="font-size:12px;color:#9CA3AF">Coffee Verve • specialty coffee Warsaw</p>
</body></html>`,

  pl: `<html><body style="font-family:sans-serif;color:#1F2937;max-width:560px;margin:auto;padding:24px">
<p style="font-size:22px;font-weight:700;margin-bottom:8px">☕ Dawno się nie widzieliśmy!</p>
<p style="color:#6B7280;margin-bottom:20px">Zauważyliśmy, że nie składałeś zamówień w Coffee Verve przez ponad 90 dni.</p>
<p style="margin-bottom:16px">W prezencie — osobisty kod rabatowy na <strong style="color:#16A34A">−20%</strong>:</p>
<div style="background:#F0FDF4;border:2px solid #86EFAC;border-radius:12px;padding:20px;text-align:center;margin-bottom:20px">
  <span style="font-size:28px;font-weight:800;letter-spacing:0.1em;color:#15803D">${code}</span>
  <p style="color:#6B7280;font-size:12px;margin-top:8px">Ważny 3 dni</p>
</div>
<a href="https://shop.coffee-verve.com/pl" style="display:block;background:#2C1810;color:#fff;text-align:center;padding:14px 24px;border-radius:10px;text-decoration:none;font-weight:600;margin-bottom:20px">Przejdź do sklepu</a>
<p style="font-size:12px;color:#9CA3AF">Coffee Verve • specialty coffee Warsaw</p>
</body></html>`,

  ua: `<html><body style="font-family:sans-serif;color:#1F2937;max-width:560px;margin:auto;padding:24px">
<p style="font-size:22px;font-weight:700;margin-bottom:8px">☕ Давно не бачились!</p>
<p style="color:#6B7280;margin-bottom:20px">Ми помітили, що ви не робили замовлень у Coffee Verve вже понад 90 днів.</p>
<p style="margin-bottom:16px">У подарунок — персональний промокод на <strong style="color:#16A34A">−20%</strong>:</p>
<div style="background:#F0FDF4;border:2px solid #86EFAC;border-radius:12px;padding:20px;text-align:center;margin-bottom:20px">
  <span style="font-size:28px;font-weight:800;letter-spacing:0.1em;color:#15803D">${code}</span>
  <p style="color:#6B7280;font-size:12px;margin-top:8px">Діє 3 дні</p>
</div>
<a href="https://shop.coffee-verve.com/ua" style="display:block;background:#2C1810;color:#fff;text-align:center;padding:14px 24px;border-radius:10px;text-decoration:none;font-weight:600;margin-bottom:20px">Перейти до магазину</a>
<p style="font-size:12px;color:#9CA3AF">Coffee Verve • specialty coffee Warsaw</p>
